(()=>{(function(){let e=document.getElementById("sidebar"),i=document.getElementById("sidebar-overlay"),n=document.getElementById("sidebar-toggle");if(!e||!i||!n)return;function a(){e.classList.add("is-open"),i.classList.add("is-visible")}function s(){e.classList.remove("is-open"),i.classList.remove("is-visible")}n.addEventListener("click",()=>{e.classList.contains("is-open")?s():a()}),i.addEventListener("click",s),e.querySelectorAll("a").forEach(t=>{t.addEventListener("click",s)});let c=window.location.pathname.split("/").pop()||"index.html";document.querySelectorAll(".sidebar__link").forEach(t=>{let o=t.getAttribute("href")||"";(o===c||c===""&&o==="index.html")&&(t.setAttribute("aria-current","page"),t.classList.add("sidebar__link--active"))})})();})();
